INSERT INTO blog_posts (id, category_id, author_id, status, cover_image_id, reading_minutes, published_at, scheduled_at, created_at, updated_at) VALUES ('dad1642d-d4d1-4bcf-bad5-16a5408e2a24', '83253037-5f33-4c76-9f00-511225131426', NULL, 'PUBLISHED', NULL, 12, '2026-05-28T00:00:00.000Z', NULL, '2026-07-09T09:27:42.515Z', '2026-07-09T09:27:42.515Z');
INSERT INTO blog_post_translations (id, post_id, locale, slug, title, excerpt, content_json, content_html, table_of_contents_json, faq_json, seo_meta_id) VALUES ('8ba4e0af-0476-4428-83de-b7918815109a', 'dad1642d-d4d1-4bcf-bad5-16a5408e2a24', 'ru', 'chto-takoe-gipnoterapiya', 'Что такое гипнотерапия и как она работает — полный гид', 'Гипнотерапия — научно обоснованный метод работы с подсознанием. Разбираем, как работает гипноз, чем отличается от эстрадного, кому подходит и какие результаты даёт.', NULL, '<p>Гипнотерапия — это метод психотерапии, который использует гипнотическое состояние (транс) для доступа к подсознанию и работы с глубинными причинами психологических проблем. Вопреки распространённым мифам, это не магия и не контроль сознания — это научно обоснованный подход с доказанной эффективностью.</p><p>В этой статье разберём, что такое гипнотерапия на самом деле, как она работает, чем отличается от "гипноза на сцене" и какие результаты можно ожидать.</p><h2>Что такое гипнотерапия?</h2><p>Гипнотерапия — это направление психотерапии, в котором терапевт использует гипноз как инструмент для работы с подсознанием клиента. В состоянии транса критическое мышление (сознание) временно отходит на второй план, открывая прямой доступ к подсознательным процессам. Важно понимать: гипнотерапия — это не гипноз "цыганский" или эстрадный. Это терапевтический процесс, который проходит в безопасной, контролируемой обстановке с полным сохранением контроля со стороны клиента.</p><p>Основные направления гипнотерапии: эриксоновский гипноз — мягкий, метафорический подход; регрессивная гипнотерапия — поиск и проработка первичной травмы; классический (директивный) гипноз — прямые внушения.</p><h2>Как работает гипнотерапия: научное объяснение</h2><p>С точки зрения нейрофизиологии, гипнотический транс — это естественное состояние изменённого сознания, в котором мозг работает на особых частотах. В этом состоянии повышается активность передней поясной коры, снижается активность дорсомедиальной префронтальной коры, усиливается связь между телом и эмоциональными центрами мозга.</p><h2>С какими проблемами работает гипнотерапия?</h2><p>Научные исследования подтверждают эффективность гипнотерапии при тревожных расстройствах, самосаботаже и прокрастинации, эмоциональном выгорании, психосоматике, личностных кризисах, работе с подсознанием.</p><p>Статья носит информационный характер и не является медицинской рекомендацией.</p>', NULL, NULL, NULL);
INSERT INTO blog_post_translations (id, post_id, locale, slug, title, excerpt, content_json, content_html, table_of_contents_json, faq_json, seo_meta_id) VALUES ('ed052c01-c430-4e92-be9f-8ac7f7058284', 'dad1642d-d4d1-4bcf-bad5-16a5408e2a24', 'uk', 'chto-takoe-gipnoterapiya', 'Что такое гипнотерапия и как она работает — полный гид', 'Гипнотерапия — научно обоснованный метод работы с подсознанием. Разбираем, как работает гипноз, чем отличается от эстрадного, кому подходит и какие результаты даёт.', NULL, '<p>Гипнотерапия — это метод психотерапии, который использует гипнотическое состояние (транс) для доступа к подсознанию и работы с глубинными причинами психологических проблем. Вопреки распространённым мифам, это не магия и не контроль сознания — это научно обоснованный подход с доказанной эффективностью.</p><p>В этой статье разберём, что такое гипнотерапия на самом деле, как она работает, чем отличается от "гипноза на сцене" и какие результаты можно ожидать.</p><h2>Что такое гипнотерапия?</h2><p>Гипнотерапия — это направление психотерапии, в котором терапевт использует гипноз как инструмент для работы с подсознанием клиента. В состоянии транса критическое мышление (сознание) временно отходит на второй план, открывая прямой доступ к подсознательным процессам. Важно понимать: гипнотерапия — это не гипноз "цыганский" или эстрадный. Это терапевтический процесс, который проходит в безопасной, контролируемой обстановке с полным сохранением контроля со стороны клиента.</p><p>Основные направления гипнотерапии: эриксоновский гипноз — мягкий, метафорический подход; регрессивная гипнотерапия — поиск и проработка первичной травмы; классический (директивный) гипноз — прямые внушения.</p><h2>Как работает гипнотерапия: научное объяснение</h2><p>С точки зрения нейрофизиологии, гипнотический транс — это естественное состояние изменённого сознания, в котором мозг работает на особых частотах. В этом состоянии повышается активность передней поясной коры, снижается активность дорсомедиальной префронтальной коры, усиливается связь между телом и эмоциональными центрами мозга.</p><h2>С какими проблемами работает гипнотерапия?</h2><p>Научные исследования подтверждают эффективность гипнотерапии при тревожных расстройствах, самосаботаже и прокрастинации, эмоциональном выгорании, психосоматике, личностных кризисах, работе с подсознанием.</p><p>Статья носит информационный характер и не является медицинской рекомендацией.</p>', NULL, NULL, NULL);
INSERT INTO blog_posts (id, category_id, author_id, status, cover_image_id, reading_minutes, published_at, scheduled_at, created_at, updated_at) VALUES ('0eec60af-5390-4686-a8cf-e0dcfd723376', '83253037-5f33-4c76-9f00-511225131426', NULL, 'PUBLISHED', NULL, 10, '2026-04-28T00:00:00.000Z', NULL, '2026-07-09T09:27:42.515Z', '2026-07-09T09:27:42.515Z');
INSERT INTO blog_post_translations (id, post_id, locale, slug, title, excerpt, content_json, content_html, table_of_contents_json, faq_json, seo_meta_id) VALUES ('140f1147-6c05-4c91-a127-1b0699162bc9', '0eec60af-5390-4686-a8cf-e0dcfd723376', 'ru', 'kak-rabotaet-gipnoz', 'Как работает гипноз — научное объяснение механизмов транса', 'Как работает гипноз с точки зрения науки и нейрофизиологии. Что происходит в мозге во время транса, почему гипноз эффективен и как он помогает менять подсознательные программы.', NULL, '<p>Гипноз окружён мифами: одни считают его магией, другие — шарлатанством, третьи — опасным инструментом контроля сознания. Реальность, как всегда, посередине. Гипноз — это естественное состояние нервной системы, которое имеет чёткое научное объяснение.</p><p>В этой статье разберём, что происходит в мозге и теле человека во время гипнотического транса, почему он работает и как это знание помогает в психотерапии.</p><h2>Что такое гипноз с научной точки зрения?</h2><p>Гипноз — это состояние изменённого сознания, характеризующееся повышенной фокусировкой внимания, снижением критического мышления и усилением восприимчивости к внушениям. Каждый из нас хотя бы раз был в лёгком трансе: когда вы "выпадаете" из реальности за рулём или читаете книгу и не слышите окружающих.</p><h2>Что происходит в мозге во время гипноза?</h2><p>Исследования с использованием фМРТ и ЭЭГ показывают чёткие изменения: повышается активность передней поясной коры (центр фокусировки), снижается активность дорсомедиальной префронтальной коры (критическое мышление), усиливается связь островковой доли с телом и эмоциями, изменяется фильтрация сигналов в таламусе.</p><h2>Почему гипноз работает в психотерапии?</h2><p>Наиболее признанная теория — теория диссоциации: в трансе сознание временно "отключает" контроль над некоторыми процессами, позволяя терапевту работать напрямую с подсознанием.</p><p>Статья носит информационный характер и не является медицинской рекомендацией.</p>', NULL, NULL, NULL);
INSERT INTO blog_post_translations (id, post_id, locale, slug, title, excerpt, content_json, content_html, table_of_contents_json, faq_json, seo_meta_id) VALUES ('75b764b0-7227-4705-b5a5-c5d4009d75ef', '0eec60af-5390-4686-a8cf-e0dcfd723376', 'uk', 'kak-rabotaet-gipnoz', 'Как работает гипноз — научное объяснение механизмов транса', 'Как работает гипноз с точки зрения науки и нейрофизиологии. Что происходит в мозге во время транса, почему гипноз эффективен и как он помогает менять подсознательные программы.', NULL, '<p>Гипноз окружён мифами: одни считают его магией, другие — шарлатанством, третьи — опасным инструментом контроля сознания. Реальность, как всегда, посередине. Гипноз — это естественное состояние нервной системы, которое имеет чёткое научное объяснение.</p><p>В этой статье разберём, что происходит в мозге и теле человека во время гипнотического транса, почему он работает и как это знание помогает в психотерапии.</p><h2>Что такое гипноз с научной точки зрения?</h2><p>Гипноз — это состояние изменённого сознания, характеризующееся повышенной фокусировкой внимания, снижением критического мышления и усилением восприимчивости к внушениям. Каждый из нас хотя бы раз был в лёгком трансе: когда вы "выпадаете" из реальности за рулём или читаете книгу и не слышите окружающих.</p><h2>Что происходит в мозге во время гипноза?</h2><p>Исследования с использованием фМРТ и ЭЭГ показывают чёткие изменения: повышается активность передней поясной коры (центр фокусировки), снижается активность дорсомедиальной префронтальной коры (критическое мышление), усиливается связь островковой доли с телом и эмоциями, изменяется фильтрация сигналов в таламусе.</p><h2>Почему гипноз работает в психотерапии?</h2><p>Наиболее признанная теория — теория диссоциации: в трансе сознание временно "отключает" контроль над некоторыми процессами, позволяя терапевту работать напрямую с подсознанием.</p><p>Статья носит информационный характер и не является медицинской рекомендацией.</p>', NULL, NULL, NULL);
INSERT INTO blog_posts (id, category_id, author_id, status, cover_image_id, reading_minutes, published_at, scheduled_at, created_at, updated_at) VALUES ('8fc7bf36-e412-42e1-9c13-1748204ad7da', '9e46b05c-83c0-45b3-b45b-4e14eea8319d', NULL, 'PUBLISHED', NULL, 11, '2026-03-26T00:00:00.000Z', NULL, '2026-07-09T09:27:42.515Z', '2026-07-09T09:27:42.515Z');
INSERT INTO blog_post_translations (id, post_id, locale, slug, title, excerpt, content_json, content_html, table_of_contents_json, faq_json, seo_meta_id) VALUES ('2f175cf5-4ecd-4fc0-9742-50d7e7447a52', '8fc7bf36-e412-42e1-9c13-1748204ad7da', 'ru', 'trevoga-prichiny-i-simptomy', 'Тревога: причины, симптомы и когда стоит обратиться к специалисту', 'Симптомы и причины тревоги: как отличить норму от расстройства, почему возникает постоянное беспокойство и какие методы помогают вернуть спокойствие.', NULL, '<p>Тревога — нормальная реакция психики на угрозу. Проблема начинается тогда, когда тревога становится хронической: вы просыпаетесь уже с беспокойством, прокручиваете в голове страхи, а тело находится в постоянном напряжении. Такое состояние не просто мешает жить — оно разрушает здоровье.</p><p>Разберём, как отличить здоровую тревогу от проблемы, какие у неё истинные причины и что делать, если тревога взяла верх.</p><h2>Симптомы тревоги: как распознать</h2><p>Тревога проявляется на трёх уровнях: физическом (учащённое сердцебиение, поверхностное дыхание, напряжение в мышцах), эмоционально-когнитивном (постоянное беспокойство, ожидание худшего, раздражительность) и поведенческом (избегание, проверка действий, откладывание дел).</p><h2>Основные причины тревоги</h2><p>Биологические факторы: повышенная активность миндалевидного тела. Психологические причины: корни в детстве, непредсказуемая среда. Подсознательные конфликты: тревога может быть сигналом внутреннего конфликта.</p><p>Статья носит информационный характер и не является медицинской рекомендацией.</p>', NULL, NULL, NULL);
INSERT INTO blog_post_translations (id, post_id, locale, slug, title, excerpt, content_json, content_html, table_of_contents_json, faq_json, seo_meta_id) VALUES ('2d69fc91-055a-4bba-803e-354a3342c5bf', '8fc7bf36-e412-42e1-9c13-1748204ad7da', 'uk', 'trevoga-prichiny-i-simptomy', 'Тревога: причины, симптомы и когда стоит обратиться к специалисту', 'Симптомы и причины тревоги: как отличить норму от расстройства, почему возникает постоянное беспокойство и какие методы помогают вернуть спокойствие.', NULL, '<p>Тревога — нормальная реакция психики на угрозу. Проблема начинается тогда, когда тревога становится хронической: вы просыпаетесь уже с беспокойством, прокручиваете в голове страхи, а тело находится в постоянном напряжении. Такое состояние не просто мешает жить — оно разрушает здоровье.</p><p>Разберём, как отличить здоровую тревогу от проблемы, какие у неё истинные причины и что делать, если тревога взяла верх.</p><h2>Симптомы тревоги: как распознать</h2><p>Тревога проявляется на трёх уровнях: физическом (учащённое сердцебиение, поверхностное дыхание, напряжение в мышцах), эмоционально-когнитивном (постоянное беспокойство, ожидание худшего, раздражительность) и поведенческом (избегание, проверка действий, откладывание дел).</p><h2>Основные причины тревоги</h2><p>Биологические факторы: повышенная активность миндалевидного тела. Психологические причины: корни в детстве, непредсказуемая среда. Подсознательные конфликты: тревога может быть сигналом внутреннего конфликта.</p><p>Статья носит информационный характер и не является медицинской рекомендацией.</p>', NULL, NULL, NULL);
INSERT INTO blog_posts (id, category_id, author_id, status, cover_image_id, reading_minutes, published_at, scheduled_at, created_at, updated_at) VALUES ('4514212d-5379-4e59-84df-3f5339db7c74', '9e46b05c-83c0-45b3-b45b-4e14eea8319d', NULL, 'PUBLISHED', NULL, 9, '2026-04-02T00:00:00.000Z', NULL, '2026-07-09T09:27:42.515Z', '2026-07-09T09:27:42.515Z');
INSERT INTO blog_post_translations (id, post_id, locale, slug, title, excerpt, content_json, content_html, table_of_contents_json, faq_json, seo_meta_id) VALUES ('879754d3-f92f-4cff-9b2e-dc7f7c12fa27', '4514212d-5379-4e59-84df-3f5339db7c74', 'ru', 'kak-spravitsya-s-trevogoy', 'Как справиться с тревогой — 5 методов, которые реально работают', 'Как справиться с тревогой: 5 действенных методов от тревоги, основанных на психологии и гипнотерапии. Практические техники для ежедневного использования.', NULL, '<p>Тревога — один из самых частых запросов, с которыми ко мне приходят клиенты. "Головой понимаю, что повода нет, а тело всё равно реагирует страхом". Знакомо? Хорошая новость: с тревогой можно работать, и методы есть разные — от быстрых техник самопомощи до глубинной проработки причин.</p><p>В этой статье — 5 методов, которые реально помогают моим клиентам.</p><h2>1. Дыхание как якорь: техника "Квадрат"</h2><p>Вдох — 4 секунды. Задержка — 4 секунды. Выдох — 4 секунды. Задержка — 4 секунды. Эта техника переключает нервную систему с симпатической на парасимпатическую.</p><h2>2. Работа с телом: снятие мышечного напряжения</h2><p>Найдите в своём теле зоны напряжения: челюсть, плечи, диафрагма. Если убрать телесный компонент тревоги, эмоциональный снизится автоматически.</p><h2>3. "Заземление": верните себя в настоящее</h2><p>Техника 5-4-3-2-1: Назовите 5 вещей, которые видите, 4 — которые чувствуете телом, 3 — которые слышите, 2 — запах, 1 — вкус.</p><h2>4. Ведение дневника тревоги</h2><p>Записывать тревожные мысли в течение дня. Часто осознания достаточно, чтобы тревога снизилась на 30-40%.</p><h2>5. Работа с первопричиной через гипнотерапию</h2><p>Методы 1-4 помогают справляться с симптомами. Но если тревога возвращается снова и снова — есть глубинная причина. Гипнотерапия позволяет найти этот корень.</p><p>Статья носит информационный характер и не является медицинской рекомендацией.</p>', NULL, NULL, NULL);
