INSERT INTO blog_posts (id, category_id, author_id, status, cover_image_id, reading_minutes, published_at, scheduled_at, created_at, updated_at) VALUES ('d5d27a72-4c9b-4dc7-bca8-0d1e8147a194', '9e46b05c-83c0-45b3-b45b-4e14eea8319d', NULL, 'PUBLISHED', NULL, 10, '2026-05-09T00:00:00.000Z', NULL, '2026-07-09T09:27:42.515Z', '2026-07-09T09:27:42.515Z');
INSERT INTO blog_post_translations (id, post_id, locale, slug, title, excerpt, content_json, content_html, table_of_contents_json, faq_json, seo_meta_id) VALUES ('0e6b0dd7-26d3-4e50-a7b4-ec309d51102a', 'd5d27a72-4c9b-4dc7-bca8-0d1e8147a194', 'ru', 'panicheskiye-ataki-chto-delat', 'Панические атаки: что делать — первая помощь и лечение', 'Панические атаки: что делать во время приступа, техники первой помощи, причины и лечение панических атак через гипнотерапию.', NULL, '<p>Паническая атака — это внезапный приступ интенсивного страха, который сопровождается физическими симптомами: сердце колотится, не хватает воздуха, тело трясётся, кажется, что вы теряете контроль или умираете. Важно понимать: паническая атака не опасна физически.</p><h2>Что делать во время панической атаки: первая помощь</h2><p>1. Переключитесь на дыхание (вдох на 4 счёта, выдох на 8). 2. Заземлитесь. 3. Не боритесь — скажите себе: "Это просто паническая атака, она пройдёт". 4. Умойтесь холодной водой.</p><h2>Почему возникают панические атаки?</h2><p>Основные причины: подавленные эмоции, гиперконтроль, травматический опыт, внутренний конфликт. По моему опыту, гипнотерапия даёт отличные результаты при панических атаках.</p><p>Статья носит информационный характер и не является медицинской рекомендацией.</p>', NULL, NULL, NULL);
INSERT INTO blog_post_translations (id, post_id, locale, slug, title, excerpt, content_json, content_html, table_of_contents_json, faq_json, seo_meta_id) VALUES ('58482d2b-dc60-4270-b71f-4fe64c55cf04', 'd5d27a72-4c9b-4dc7-bca8-0d1e8147a194', 'uk', 'panicheskiye-ataki-chto-delat', 'Панические атаки: что делать — первая помощь и лечение', 'Панические атаки: что делать во время приступа, техники первой помощи, причины и лечение панических атак через гипнотерапию.', NULL, '<p>Паническая атака — это внезапный приступ интенсивного страха, который сопровождается физическими симптомами: сердце колотится, не хватает воздуха, тело трясётся, кажется, что вы теряете контроль или умираете. Важно понимать: паническая атака не опасна физически.</p><h2>Что делать во время панической атаки: первая помощь</h2><p>1. Переключитесь на дыхание (вдох на 4 счёта, выдох на 8). 2. Заземлитесь. 3. Не боритесь — скажите себе: "Это просто паническая атака, она пройдёт". 4. Умойтесь холодной водой.</p><h2>Почему возникают панические атаки?</h2><p>Основные причины: подавленные эмоции, гиперконтроль, травматический опыт, внутренний конфликт. По моему опыту, гипнотерапия даёт отличные результаты при панических атаках.</p><p>Статья носит информационный характер и не является медицинской рекомендацией.</p>', NULL, NULL, NULL);
INSERT INTO blog_posts (id, category_id, author_id, status, cover_image_id, reading_minutes, published_at, scheduled_at, created_at, updated_at) VALUES ('4c7f718a-ec9c-4770-889c-e61d46dbb31f', 'c3bf4ef4-53fc-4395-890f-1bc8af88d114', NULL, 'PUBLISHED', NULL, 10, '2026-05-19T00:00:00.000Z', NULL, '2026-07-09T09:27:42.515Z', '2026-07-09T09:27:42.515Z');
INSERT INTO blog_post_translations (id, post_id, locale, slug, title, excerpt, content_json, content_html, table_of_contents_json, faq_json, seo_meta_id) VALUES ('276109ed-cc72-46f6-a7da-e39fb842a7d6', '4c7f718a-ec9c-4770-889c-e61d46dbb31f', 'ru', 'chto-takoe-samosabotazh', 'Самосаботаж: что это такое и как проявляется в жизни', 'Самосаботаж — что это, как проявляется, почему вы откладываете важное и саботируете свои цели. Причины самосаботажа и методы работы через гипнотерапию.', NULL, '<p>Самосаботаж — это когда вы осознанно хотите достичь цели, но бессознательно делаете всё, чтобы её не достичь. Вы ставите задачу, но находите тысячу причин её не делать. Самосаботаж — одна из самых частых причин, по которым люди не достигают своих целей.</p><h2>Как проявляется самосаботаж?</h2><p>Прокрастинация, перфекционизм, срыв сроков, саботаж отношений, саботаж здоровья, синдром самозванца.</p><h2>Почему мы саботируем себя?</h2><p>Страх успеха, страх неудачи, внутреннее убеждение "я недостоин", травма прошлого, конфликт между "хочу" и "надо".</p><h2>Как работать с самосаботажем?</h2><p>1. Осознать паттерн. 2. Познакомиться с "внутренним саботажником". 3. Работа с подсознанием через гипнотерапию.</p><p>Статья носит информационный характер и не является медицинской рекомендацией.</p>', NULL, NULL, NULL);
INSERT INTO blog_post_translations (id, post_id, locale, slug, title, excerpt, content_json, content_html, table_of_contents_json, faq_json, seo_meta_id) VALUES ('53eb94b2-af94-41f8-8ff0-78760a68eda1', '4c7f718a-ec9c-4770-889c-e61d46dbb31f', 'uk', 'chto-takoe-samosabotazh', 'Самосаботаж: что это такое и как проявляется в жизни', 'Самосаботаж — что это, как проявляется, почему вы откладываете важное и саботируете свои цели. Причины самосаботажа и методы работы через гипнотерапию.', NULL, '<p>Самосаботаж — это когда вы осознанно хотите достичь цели, но бессознательно делаете всё, чтобы её не достичь. Вы ставите задачу, но находите тысячу причин её не делать. Самосаботаж — одна из самых частых причин, по которым люди не достигают своих целей.</p><h2>Как проявляется самосаботаж?</h2><p>Прокрастинация, перфекционизм, срыв сроков, саботаж отношений, саботаж здоровья, синдром самозванца.</p><h2>Почему мы саботируем себя?</h2><p>Страх успеха, страх неудачи, внутреннее убеждение "я недостоин", травма прошлого, конфликт между "хочу" и "надо".</p><h2>Как работать с самосаботажем?</h2><p>1. Осознать паттерн. 2. Познакомиться с "внутренним саботажником". 3. Работа с подсознанием через гипнотерапию.</p><p>Статья носит информационный характер и не является медицинской рекомендацией.</p>', NULL, NULL, NULL);
INSERT INTO blog_posts (id, category_id, author_id, status, cover_image_id, reading_minutes, published_at, scheduled_at, created_at, updated_at) VALUES ('54f37996-fda4-4bcb-84b9-87b3101ca4c1', 'c3bf4ef4-53fc-4395-890f-1bc8af88d114', NULL, 'PUBLISHED', NULL, 9, '2026-05-22T00:00:00.000Z', NULL, '2026-07-09T09:27:42.515Z', '2026-07-09T09:27:42.515Z');
INSERT INTO blog_post_translations (id, post_id, locale, slug, title, excerpt, content_json, content_html, table_of_contents_json, faq_json, seo_meta_id) VALUES ('595791b0-67ae-4547-a7e6-686242abe149', '54f37996-fda4-4bcb-84b9-87b3101ca4c1', 'ru', 'samosabotazh-prichiny', 'Причины самосаботажа: психология и роль подсознания', 'Глубинные причины самосаботажа: психология подсознания, внутренние конфликты, страх успеха и неудачи. Как гипнотерапия помогает убрать корень проблемы.', NULL, '<p>Почему мы саботируем то, что для нас важно? Ответ лежит в подсознании — там, где наши глубинные убеждения, страхи и конфликты управляют поведением без нашего ведома. В этой статье разберём основные причины самосаботажа на уровне подсознания.</p><h2>Страх успеха: парадокс самосаботажа</h2><p>Когда ваше сознание стремится к успеху, но подсознание его боится — возникает конфликт. Самосаботаж — это способ подсознания "защитить" вас от успеха.</p><h2>Внутренние убеждения из детства</h2><p>Большинство причин самосаботажа — из детства. Ваше подсознание впитало установки как истину. Конфликт между желанием и установкой называется самосаботажем.</p><p>Статья носит информационный характер и не является медицинской рекомендацией.</p>', NULL, NULL, NULL);
INSERT INTO blog_post_translations (id, post_id, locale, slug, title, excerpt, content_json, content_html, table_of_contents_json, faq_json, seo_meta_id) VALUES ('754c52ff-4b5c-4cf8-b101-d2b449ec5b43', '54f37996-fda4-4bcb-84b9-87b3101ca4c1', 'uk', 'samosabotazh-prichiny', 'Причины самосаботажа: психология и роль подсознания', 'Глубинные причины самосаботажа: психология подсознания, внутренние конфликты, страх успеха и неудачи. Как гипнотерапия помогает убрать корень проблемы.', NULL, '<p>Почему мы саботируем то, что для нас важно? Ответ лежит в подсознании — там, где наши глубинные убеждения, страхи и конфликты управляют поведением без нашего ведома. В этой статье разберём основные причины самосаботажа на уровне подсознания.</p><h2>Страх успеха: парадокс самосаботажа</h2><p>Когда ваше сознание стремится к успеху, но подсознание его боится — возникает конфликт. Самосаботаж — это способ подсознания "защитить" вас от успеха.</p><h2>Внутренние убеждения из детства</h2><p>Большинство причин самосаботажа — из детства. Ваше подсознание впитало установки как истину. Конфликт между желанием и установкой называется самосаботажем.</p><p>Статья носит информационный характер и не является медицинской рекомендацией.</p>', NULL, NULL, NULL);
