INSERT INTO blog_post_translations (id, post_id, locale, slug, title, excerpt, content_json, content_html, table_of_contents_json, faq_json, seo_meta_id) VALUES ('025f1a8e-0e0b-42ac-8283-4b0636d47e6c', 'b10d1e77-34a5-4a27-a1dc-25d2be860266', 'ru', 'emotsionalnoye-vygoraniye-simptomy', 'Эмоциональное выгорание: признаки, причины и как восстановиться', 'Признаки эмоционального выгорания: как распознать, чем отличается от усталости, причины выгорания и методы восстановления через гипнотерапию.', NULL, '<p>"Сил нет вообще" — эта фраза звучит от моих клиентов на каждой второй консультации. Не просто устал, а именно выгорел: когда энергия закончилась, интерес пропал, а чувство "надо" осталось. Эмоциональное выгорание — это синдром, вызванный длительным стрессом, который не получил разрядки.</p><h2>Признаки эмоционального выгорания</h2><p>Физические: хроническая усталость, сниженный иммунитет, головные боли. Эмоциональные: чувство опустошённости, потеря интереса, раздражительность, цинизм. Поведенческие: снижение продуктивности, избегание общения, прокрастинация.</p><h2>Чем выгорание отличается от обычной усталости?</h2><p>Усталость проходит после отдыха. Выгорание не проходит после сна или отпуска — его причина в длительном дисбалансе.</p><h2>Как восстановиться после выгорания?</h2><p>1. Отдых — не роскошь, а необходимость. 2. Верните контакт с телом. 3. Работа с причиной через гипнотерапию.</p><p>Статья носит информационный характер и не является медицинской рекомендацией.</p>', NULL, NULL, NULL);
