INSERT INTO blog_posts (id, category_id, author_id, status, cover_image_id, reading_minutes, published_at, scheduled_at, created_at, updated_at) VALUES ('12f5d01b-eb20-4b54-9321-a3928f43e37b', 'c3bf4ef4-53fc-4395-890f-1bc8af88d114', NULL, 'PUBLISHED', NULL, 9, '2026-05-30T00:00:00.000Z', NULL, '2026-07-09T09:27:42.515Z', '2026-07-09T09:27:42.515Z');
INSERT INTO blog_post_translations (id, post_id, locale, slug, title, excerpt, content_json, content_html, table_of_contents_json, faq_json, seo_meta_id) VALUES ('ea4b2d42-2517-455c-b0b8-958b149c8dca', '12f5d01b-eb20-4b54-9321-a3928f43e37b', 'ru', 'vnutrenniy-kritik', 'Внутренний критик: психология, влияние на самооценку и как его приручить', 'Внутренний критик в психологии — откуда берётся, как влияет на самооценку и жизнь. Техники работы с критиком и помощь гипнотерапии.', NULL, '<p>Внутренний критик — это голос внутри, который оценивает, критикует, обесценивает: "Ты недостаточно хорош", "У тебя не получится", "Стыдно так плохо делать". Для многих этот голос звучит так часто, что они перестали его замечать.</p><h2>Откуда берётся внутренний критик?</h2><p>Внутренний критик формируется в детстве как результат интроекции. Если ребёнка часто критиковали, сравнивали с другими — его психика создала защитный механизм.</p><h2>Как внутренний критик влияет на жизнь?</h2><p>Самооценка, синдром самозванца, прокрастинация, тревога, отношения.</p><h2>Приручение внутреннего критика: первые шаги</h2><p>1. Заметьте его. 2. Познакомьтесь с ним. 3. Отделите факты от интерпретации. 4. Практикуйте самосострадание.</p><p>Статья носит информационный характер и не является медицинской рекомендацией.</p>', NULL, NULL, NULL);
INSERT INTO blog_post_translations (id, post_id, locale, slug, title, excerpt, content_json, content_html, table_of_contents_json, faq_json, seo_meta_id) VALUES ('ceccd687-62cf-4f53-b826-74aa022c1f68', '12f5d01b-eb20-4b54-9321-a3928f43e37b', 'uk', 'vnutrenniy-kritik', 'Внутренний критик: психология, влияние на самооценку и как его приручить', 'Внутренний критик в психологии — откуда берётся, как влияет на самооценку и жизнь. Техники работы с критиком и помощь гипнотерапии.', NULL, '<p>Внутренний критик — это голос внутри, который оценивает, критикует, обесценивает: "Ты недостаточно хорош", "У тебя не получится", "Стыдно так плохо делать". Для многих этот голос звучит так часто, что они перестали его замечать.</p><h2>Откуда берётся внутренний критик?</h2><p>Внутренний критик формируется в детстве как результат интроекции. Если ребёнка часто критиковали, сравнивали с другими — его психика создала защитный механизм.</p><h2>Как внутренний критик влияет на жизнь?</h2><p>Самооценка, синдром самозванца, прокрастинация, тревога, отношения.</p><h2>Приручение внутреннего критика: первые шаги</h2><p>1. Заметьте его. 2. Познакомьтесь с ним. 3. Отделите факты от интерпретации. 4. Практикуйте самосострадание.</p><p>Статья носит информационный характер и не является медицинской рекомендацией.</p>', NULL, NULL, NULL);
