INSERT INTO blog_post_translations (id, post_id, locale, slug, title, excerpt, content_json, content_html, table_of_contents_json, faq_json, seo_meta_id) VALUES ('85786198-407b-49a9-81e8-da3524d4c125', 'd9e9f23e-dcb8-41b4-9f94-7de54436909d', 'ru', 'podavlennyye-emotsii', 'Подавленные эмоции: последствия для психики и тела', 'Подавленные эмоции и их последствия: как подавление чувств влияет на психику, тело и поведение. Психосоматика, тревога, выгорание — и как гипнотерапия помогает.', NULL, '<p>"Не плачь", "Не злись", "Возьми себя в руки" — многие из нас выросли с посланием, что некоторые эмоции нужно подавлять. Проблема в том, что подавленная эмоция никуда не девается. Она остаётся в теле, в подсознании и продолжает влиять на жизнь.</p><h2>Последствия подавления эмоций</h2><p>Психосоматика (тело берёт на себя то, что психика не смогла переработать), тревога и панические атаки, эмоциональные "взрывы", депрессия и апатия.</p><h2>Как работать с подавленными эмоциями?</h2><p>1. Создать безопасное пространство. 2. Через тело. 3. Через подсознание — в гипнотерапии.</p><p>Статья носит информационный характер и не является медицинской рекомендацией.</p>', NULL, NULL, NULL);
INSERT INTO blog_post_translations (id, post_id, locale, slug, title, excerpt, content_json, content_html, table_of_contents_json, faq_json, seo_meta_id) VALUES ('665a7a24-cb3a-4d87-aa0d-38c34279c6d2', 'd9e9f23e-dcb8-41b4-9f94-7de54436909d', 'uk', 'podavlennyye-emotsii', 'Подавленные эмоции: последствия для психики и тела', 'Подавленные эмоции и их последствия: как подавление чувств влияет на психику, тело и поведение. Психосоматика, тревога, выгорание — и как гипнотерапия помогает.', NULL, '<p>"Не плачь", "Не злись", "Возьми себя в руки" — многие из нас выросли с посланием, что некоторые эмоции нужно подавлять. Проблема в том, что подавленная эмоция никуда не девается. Она остаётся в теле, в подсознании и продолжает влиять на жизнь.</p><h2>Последствия подавления эмоций</h2><p>Психосоматика (тело берёт на себя то, что психика не смогла переработать), тревога и панические атаки, эмоциональные "взрывы", депрессия и апатия.</p><h2>Как работать с подавленными эмоциями?</h2><p>1. Создать безопасное пространство. 2. Через тело. 3. Через подсознание — в гипнотерапии.</p><p>Статья носит информационный характер и не является медицинской рекомендацией.</p>', NULL, NULL, NULL);
