INSERT INTO blog_post_translations (id, post_id, locale, slug, title, excerpt, content_json, content_html, table_of_contents_json, faq_json, seo_meta_id) VALUES ('102cd41c-322b-410f-8323-e48d9815f465', 'e423f834-85d5-444f-b339-4ad23103ffeb', 'ru', 'eksistentsialnyy-krizis', 'Экзистенциальный кризис: что это и как найти опору', 'Экзистенциальный кризис — потеря смысла жизни, "кто я", кризис самоопределения. Причины, симптомы и как гипнотерапия помогает найти внутреннюю опору.', NULL, '<p>"Вроде всё есть, а радости нет", "Я не понимаю, куда мне двигаться", "Кажется, я живу не свою жизнь" — это голос экзистенциального кризиса. Экзистенциальный кризис — это не болезнь и не расстройство. Это естественный этап развития личности.</p><h2>Признаки экзистенциального кризиса</h2><p>Ощущение пустоты, вопросы "зачем?", потеря интереса, чувство что вы "идёте не по тому пути", тревога о времени, желание всё изменить.</p><h2>Что делать во время кризиса?</h2><p>1. Не избегать. 2. Искать не ответы, а вопросы. 3. Вернуться в тело. 4. Обратиться за поддержкой.</p><p>Статья носит информационный характер и не является медицинской рекомендацией.</p>', NULL, NULL, NULL);
INSERT INTO blog_post_translations (id, post_id, locale, slug, title, excerpt, content_json, content_html, table_of_contents_json, faq_json, seo_meta_id) VALUES ('a88ca204-fb78-4408-9745-b566d6668795', 'e423f834-85d5-444f-b339-4ad23103ffeb', 'uk', 'eksistentsialnyy-krizis', 'Экзистенциальный кризис: что это и как найти опору', 'Экзистенциальный кризис — потеря смысла жизни, "кто я", кризис самоопределения. Причины, симптомы и как гипнотерапия помогает найти внутреннюю опору.', NULL, '<p>"Вроде всё есть, а радости нет", "Я не понимаю, куда мне двигаться", "Кажется, я живу не свою жизнь" — это голос экзистенциального кризиса. Экзистенциальный кризис — это не болезнь и не расстройство. Это естественный этап развития личности.</p><h2>Признаки экзистенциального кризиса</h2><p>Ощущение пустоты, вопросы "зачем?", потеря интереса, чувство что вы "идёте не по тому пути", тревога о времени, желание всё изменить.</p><h2>Что делать во время кризиса?</h2><p>1. Не избегать. 2. Искать не ответы, а вопросы. 3. Вернуться в тело. 4. Обратиться за поддержкой.</p><p>Статья носит информационный характер и не является медицинской рекомендацией.</p>', NULL, NULL, NULL);
