INSERT INTO blog_post_translations (id, post_id, locale, slug, title, excerpt, content_json, content_html, table_of_contents_json, faq_json, seo_meta_id) VALUES ('cbff5f30-ccba-4adf-84e1-f30a948ba609', 'a52468c8-7a8a-49b5-98bd-1b1a94e371ca', 'ru', 'gipnoterapiya-onlayn-kak-prokhodit', 'Онлайн-гипноз: как проходит сессия, безопасность и эффективность', 'Онлайн-гипноз: как проходит сессия гипнотерапии через видеосвязь, безопасность, эффективность по исследованиям, что нужно для сессии.', NULL, '<p>"Работает ли гипноз через экран?" — один из самых частых вопросов. Интуитивно кажется, что для гипноза нужно присутствие "вживую". Но исследования и многолетняя практика говорят об обратном.</p><h2>Как проходит онлайн-сессия гипнотерапии?</h2><p>1. Подготовка (тихое место, 60 минут). 2. Обсуждение запроса (10-15 мин). 3. Наведение транса (5-10 мин). 4. Трансовая работа (25-35 мин). 5. Выход из транса (3-5 мин).</p><h2>Безопасен ли онлайн-гипноз?</h2><p>Да. Вы контролируете процесс, находитесь в безопасной среде, сессии через защищённые каналы.</p><h2>Эффективность: что говорят исследования?</h2><p>Онлайн-гипнотерапия не уступает очной по эффективности. Глубина транса, скорость работы, устойчивость результата — всё сопоставимо.</p><p>Статья носит информационный характер и не является медицинской рекомендацией.</p>', NULL, NULL, NULL);
INSERT INTO blog_post_translations (id, post_id, locale, slug, title, excerpt, content_json, content_html, table_of_contents_json, faq_json, seo_meta_id) VALUES ('c5fc4abd-eda5-41c5-97fd-fce58dddf8d2', 'a52468c8-7a8a-49b5-98bd-1b1a94e371ca', 'uk', 'gipnoterapiya-onlayn-kak-prokhodit', 'Онлайн-гипноз: как проходит сессия, безопасность и эффективность', 'Онлайн-гипноз: как проходит сессия гипнотерапии через видеосвязь, безопасность, эффективность по исследованиям, что нужно для сессии.', NULL, '<p>"Работает ли гипноз через экран?" — один из самых частых вопросов. Интуитивно кажется, что для гипноза нужно присутствие "вживую". Но исследования и многолетняя практика говорят об обратном.</p><h2>Как проходит онлайн-сессия гипнотерапии?</h2><p>1. Подготовка (тихое место, 60 минут). 2. Обсуждение запроса (10-15 мин). 3. Наведение транса (5-10 мин). 4. Трансовая работа (25-35 мин). 5. Выход из транса (3-5 мин).</p><h2>Безопасен ли онлайн-гипноз?</h2><p>Да. Вы контролируете процесс, находитесь в безопасной среде, сессии через защищённые каналы.</p><h2>Эффективность: что говорят исследования?</h2><p>Онлайн-гипнотерапия не уступает очной по эффективности. Глубина транса, скорость работы, устойчивость результата — всё сопоставимо.</p><p>Статья носит информационный характер и не является медицинской рекомендацией.</p>', NULL, NULL, NULL);
INSERT INTO blog_posts (id, category_id, author_id, status, cover_image_id, reading_minutes, published_at, scheduled_at, created_at, updated_at) VALUES ('966e891e-76b6-4e3a-9f18-edca4afb5a93', '0a038302-e133-43bf-8520-8a3924a262fa', NULL, 'PUBLISHED', NULL, 10, '2026-04-01T00:00:00.000Z', NULL, '2026-07-09T09:27:42.515Z', '2026-07-09T09:27:42.515Z');
INSERT INTO blog_post_translations (id, post_id, locale, slug, title, excerpt, content_json, content_html, table_of_contents_json, faq_json, seo_meta_id) VALUES ('00331f67-5695-42b2-8315-950498ff7eb5', '966e891e-76b6-4e3a-9f18-edca4afb5a93', 'ru', 'priznaki-gadzhet-zavisimosti', 'Как понять, что у вас зависимость от телефона — 10 признаков', 'Гаджетозависимость: 10 признаков, что телефон управляет вашей жизнью. Как отличить привычку от зависимости, симптомы номофобии, думскроллинга и FOMO.', NULL, '<p>Вы берёте телефон в руки, чтобы проверить одно сообщение, — и обнаруживаете себя через час в ленте. Вы ложитесь спать в 11 вечера, но "ещё пять минут" превращаются в час. Знакомо?</p><h2>10 признаков гаджетозависимости</h2><p>1. Проверка телефона без причины. 2. Тревога без телефона (номофобия). 3. Думскроллинг. 4. FOMO. 5. Телефон — первое утром и последнее вечером. 6. Потеря времени. 7. Мешает работе. 8. Снижение живого общения. 9. Срывы при попытках ограничить. 10. Физические симптомы.</p><p>Статья носит информационный характер и не является медицинской рекомендацией.</p>', NULL, NULL, NULL);
INSERT INTO blog_post_translations (id, post_id, locale, slug, title, excerpt, content_json, content_html, table_of_contents_json, faq_json, seo_meta_id) VALUES ('c2abd0a5-30af-42a2-a3d4-ca15e656b058', '966e891e-76b6-4e3a-9f18-edca4afb5a93', 'uk', 'priznaki-gadzhet-zavisimosti', 'Как понять, что у вас зависимость от телефона — 10 признаков', 'Гаджетозависимость: 10 признаков, что телефон управляет вашей жизнью. Как отличить привычку от зависимости, симптомы номофобии, думскроллинга и FOMO.', NULL, '<p>Вы берёте телефон в руки, чтобы проверить одно сообщение, — и обнаруживаете себя через час в ленте. Вы ложитесь спать в 11 вечера, но "ещё пять минут" превращаются в час. Знакомо?</p><h2>10 признаков гаджетозависимости</h2><p>1. Проверка телефона без причины. 2. Тревога без телефона (номофобия). 3. Думскроллинг. 4. FOMO. 5. Телефон — первое утром и последнее вечером. 6. Потеря времени. 7. Мешает работе. 8. Снижение живого общения. 9. Срывы при попытках ограничить. 10. Физические симптомы.</p><p>Статья носит информационный характер и не является медицинской рекомендацией.</p>', NULL, NULL, NULL);
INSERT INTO blog_posts (id, category_id, author_id, status, cover_image_id, reading_minutes, published_at, scheduled_at, created_at, updated_at) VALUES ('c50c1019-a610-4104-b2dc-b3a2cb618952', '0a038302-e133-43bf-8520-8a3924a262fa', NULL, 'PUBLISHED', NULL, 12, '2026-06-01T00:00:00.000Z', NULL, '2026-07-09T09:27:42.515Z', '2026-07-09T09:27:42.515Z');
INSERT INTO blog_post_translations (id, post_id, locale, slug, title, excerpt, content_json, content_html, table_of_contents_json, faq_json, seo_meta_id) VALUES ('7a35290f-0c23-4555-b197-4d2f13638ad0', 'c50c1019-a610-4104-b2dc-b3a2cb618952', 'ru', 'tsifrovoy-detoks-poshagovoe-rukovodstvo', 'Цифровой детокс: пошаговое руководство по очищению от гаджетов', 'Пошаговое руководство по цифровому детоксу: как провести день без телефона, правила цифровой гигиены, приложения-помощники и как закрепить результат.', NULL, '<p>Среднестатистический человек проводит в телефоне 5-7 часов в день. Цифровой детокс — это осознанное ограничение использования цифровых устройств на определённый период.</p><h2>Шаг 1. Аудит: сколько времени вы реально проводите в телефоне</h2><p>Включите экранное время и посмотрите статистику за неделю.</p><h2>Шаг 2. Подготовка окружения</h2><p>Удалите приложения-пожиратели времени, отключите уведомления, включите чёрно-белый режим, уберите телефон из спальни.</p><h2>Шаг 3. Детокс-день: 24 часа без телефона</h2><p>Выберите один день для полного отключения от цифрового мира.</p><h2>Шаг 4. Правила цифровой гигиены</h2><p>Правило 20-20-20, без телефона за столом, час до сна без экрана.</p><h2>Шаг 5. Работа с глубинными причинами</h2><p>Если срываетесь снова и снова — причина не в силе воли. Гипнотерапия убирает внутреннюю тягу к экрану.</p><p>Статья носит информационный характер и не является медицинской рекомендацией.</p>', NULL, NULL, NULL);
INSERT INTO blog_post_translations (id, post_id, locale, slug, title, excerpt, content_json, content_html, table_of_contents_json, faq_json, seo_meta_id) VALUES ('0c0084e1-67ec-4a81-bc4f-4656105e0b83', 'c50c1019-a610-4104-b2dc-b3a2cb618952', 'uk', 'tsifrovoy-detoks-poshagovoe-rukovodstvo', 'Цифровой детокс: пошаговое руководство по очищению от гаджетов', 'Пошаговое руководство по цифровому детоксу: как провести день без телефона, правила цифровой гигиены, приложения-помощники и как закрепить результат.', NULL, '<p>Среднестатистический человек проводит в телефоне 5-7 часов в день. Цифровой детокс — это осознанное ограничение использования цифровых устройств на определённый период.</p><h2>Шаг 1. Аудит: сколько времени вы реально проводите в телефоне</h2><p>Включите экранное время и посмотрите статистику за неделю.</p><h2>Шаг 2. Подготовка окружения</h2><p>Удалите приложения-пожиратели времени, отключите уведомления, включите чёрно-белый режим, уберите телефон из спальни.</p><h2>Шаг 3. Детокс-день: 24 часа без телефона</h2><p>Выберите один день для полного отключения от цифрового мира.</p><h2>Шаг 4. Правила цифровой гигиены</h2><p>Правило 20-20-20, без телефона за столом, час до сна без экрана.</p><h2>Шаг 5. Работа с глубинными причинами</h2><p>Если срываетесь снова и снова — причина не в силе воли. Гипнотерапия убирает внутреннюю тягу к экрану.</p><p>Статья носит информационный характер и не является медицинской рекомендацией.</p>', NULL, NULL, NULL);
INSERT INTO blog_posts (id, category_id, author_id, status, cover_image_id, reading_minutes, published_at, scheduled_at, created_at, updated_at) VALUES ('d52d71e1-0963-4441-9f6e-c9ad78d5dde5', '889596c9-9768-4493-a357-31f6df43f607', NULL, 'PUBLISHED', NULL, 12, '2026-04-18T00:00:00.000Z', NULL, '2026-07-09T09:27:42.515Z', '2026-07-09T09:27:42.515Z');
INSERT INTO blog_post_translations (id, post_id, locale, slug, title, excerpt, content_json, content_html, table_of_contents_json, faq_json, seo_meta_id) VALUES ('0df15c0c-ec6a-4fd3-8b97-502b8a6a65b8', 'd52d71e1-0963-4441-9f6e-c9ad78d5dde5', 'ru', 'net-sil-chto-delat', 'Нет сил — что делать? Психосоматика усталости и как вернуть энергию', 'Что делать, если постоянно нет сил, апатия и ничего не хочется: разбор глубинных психологических причин хронической усталости.', NULL, '<p>Вы спите по 8-10 часов, пьёте витамины, сдали все анализы, и врачи говорят, что вы здоровы, но утром вы всё равно просыпаетесь уставшим. Обычный совет "просто отдохни" не работает.</p><h2>Куда уходит жизненная энергия: 4 главные подсознательные причины</h2><p>1. Внутренний конфликт и самосаботаж. 2. Подавленные эмоции. 3. Хроническая тревога и гиперконтроль. 4. Синдром выученной беспомощности.</p><h2>Как вернуть силы: пошаговый план</h2><p>Проведите аудит "сверхконтроля", разрешите себе легальный "ноль", найдите скрытую выгоду от усталости. Если корень проблемы глубоко — гипнотерапия помогает.</p><p>Статья носит информационный характер и не является медицинской рекомендацией.</p>', NULL, NULL, NULL);
