INSERT INTO blog_posts (id, category_id, author_id, status, cover_image_id, reading_minutes, published_at, scheduled_at, created_at, updated_at) VALUES ('f344e86c-f2c6-4cb2-b4dc-9b06d6df9460', '889596c9-9768-4493-a357-31f6df43f607', NULL, 'PUBLISHED', NULL, 14, '2026-06-07T00:00:00.000Z', NULL, '2026-07-09T09:27:42.515Z', '2026-07-09T09:27:42.515Z');
INSERT INTO blog_post_translations (id, post_id, locale, slug, title, excerpt, content_json, content_html, table_of_contents_json, faq_json, seo_meta_id) VALUES ('85fddc90-985b-43e0-84ac-d67dfeb802ec', 'f344e86c-f2c6-4cb2-b4dc-9b06d6df9460', 'ru', 'vliyanie-pesen-na-podsoznanie', 'Влияние песен на подсознание: как музыка меняет наши мысли, эмоции и поведение', 'Как музыка и песни влияют на подсознание: нейрофизиология восприятия, влияние частот и ритмов, почему одни песни вызывают мурашки, а другие — тревогу.', NULL, '<p>Вы когда-нибудь замечали, как одна песня может мгновенно изменить ваше состояние? Это не магия. Это прямое действие музыки на ваше подсознание. Звук — единственный сенсорный канал, который обрабатывается мозгом до того, как сознание успевает включить фильтр критики.</p><h2>Почему музыка минует сознание и идёт прямо в подсознание?</h2><p>Слух — единственное чувство, которое не имеет "выключателя". Информация о звуке поступает в таламус и лимбическую систему за 8-10 миллисекунд. Это значит, что музыка воздействует на ваши эмоции до того, как вы это осознаёте.</p><h2>Как именно песни влияют на подсознание: 4 ключевых механизма</h2><p>1. Частота и вибрация — настройка мозга. 2. Ритм — синхронизация тела и психики. 3. Мелодия и гармония — язык эмоций. 4. Текст — прямое внушение.</p><p>В своей практике я часто использую музыку как вспомогательный инструмент в гипнотерапии.</p><p>Статья носит информационный характер и не является медицинской рекомендацией.</p>', NULL, NULL, NULL);
