INSERT INTO blog_posts (id, category_id, author_id, status, cover_image_id, reading_minutes, published_at, scheduled_at, created_at, updated_at) VALUES ('02747b13-e167-425b-bd72-9dde29978640', '0a038302-e133-43bf-8520-8a3924a262fa', NULL, 'PUBLISHED', NULL, 11, '2026-02-01T00:00:00.000Z', NULL, '2026-07-09T09:27:42.515Z', '2026-07-09T09:27:42.515Z');
INSERT INTO blog_post_translations (id, post_id, locale, slug, title, excerpt, content_json, content_html, table_of_contents_json, faq_json, seo_meta_id) VALUES ('87ac4db6-8d5a-4efd-b129-fa387579cd3c', '02747b13-e167-425b-bd72-9dde29978640', 'ru', 'detskaya-gadzhet-zavisimost', 'Ребёнок постоянно в телефоне: что делать родителям — советы психолога', 'Ребёнок постоянно в телефоне — что делать? Нормы экранного времени для детей, признаки зависимости, практические советы психолога и когда нужна помощь специалиста.', NULL, '<p>"Сын просыпается — сразу берёт телефон. Ест — с телефоном. Делает уроки — телефон лежит рядом. Мы пробовали забирать, ругаться, наказывать — ничего не работает." Это описание — не единичный случай. Ко мне приходят родители с этим запросом всё чаще.</p><h2>Почему дети "подсаживаются" на телефон?</h2><p>Нейрофизиологические причины: мозг ребёнка особенно чувствителен к дофамину. Психологические: телефон становится убежищем от проблем.</p><h2>Что делать: пошаговая стратегия для родителей</h2><p>1. Не запрещать — договариваться. 2. Заменить, а не отобрать. 3. Быть примером. 4. Создать "зоны без телефона". 5. Использовать родительский контроль с умом. 6. Разобраться с причиной.</p><p>Статья носит информационный характер и не является медицинской рекомендацией.</p>', NULL, NULL, NULL);
INSERT INTO blog_post_translations (id, post_id, locale, slug, title, excerpt, content_json, content_html, table_of_contents_json, faq_json, seo_meta_id) VALUES ('760277cb-7b3b-4879-8eb6-f115700ac47c', '02747b13-e167-425b-bd72-9dde29978640', 'uk', 'detskaya-gadzhet-zavisimost', 'Ребёнок постоянно в телефоне: что делать родителям — советы психолога', 'Ребёнок постоянно в телефоне — что делать? Нормы экранного времени для детей, признаки зависимости, практические советы психолога и когда нужна помощь специалиста.', NULL, '<p>"Сын просыпается — сразу берёт телефон. Ест — с телефоном. Делает уроки — телефон лежит рядом. Мы пробовали забирать, ругаться, наказывать — ничего не работает." Это описание — не единичный случай. Ко мне приходят родители с этим запросом всё чаще.</p><h2>Почему дети "подсаживаются" на телефон?</h2><p>Нейрофизиологические причины: мозг ребёнка особенно чувствителен к дофамину. Психологические: телефон становится убежищем от проблем.</p><h2>Что делать: пошаговая стратегия для родителей</h2><p>1. Не запрещать — договариваться. 2. Заменить, а не отобрать. 3. Быть примером. 4. Создать "зоны без телефона". 5. Использовать родительский контроль с умом. 6. Разобраться с причиной.</p><p>Статья носит информационный характер и не является медицинской рекомендацией.</p>', NULL, NULL, NULL);
