INSERT INTO blog_post_translations (id, post_id, locale, slug, title, excerpt, content_json, content_html, table_of_contents_json, faq_json, seo_meta_id) VALUES ('a8bf8c90-8929-4287-a995-2d3325b5cb31', '416aceca-de93-4cf5-835f-a6b4fa0d965a', 'ru', 'postoyannaya-ustalost-prichiny', 'Постоянная усталость: подсознательные причины и как от них избавиться', 'Почему постоянная усталость не проходит даже после отдыха: психосоматические и подсознательные причины. Как гипнотерапия помогает восстановить энергию.', NULL, '<p>Вы высыпаетесь, берёте выходной, едете в отпуск — а усталость никуда не исчезает. Постоянная усталость, которая не проходит после отдыха, — это сигнал подсознания о накопленных конфликтах, подавленных эмоциях и разрушительных убеждениях.</p><h2>5 подсознательных причин постоянной усталости</h2><p>1. Хронический стресс в фоновом режиме. 2. Подавленные эмоции. 3. Деструктивные убеждения. 4. Незавершённые внутренние конфликты. 5. Скрытая вторичная выгода от усталости.</p><h2>Как гипнотерапия работает с причинами хронической усталости</h2><p>В гипнотерапии мы находим и нейтрализуем внутренний конфликт, проживаем и выпускаем заблокированные эмоции, перепрограммируем установки выученной беспомощности.</p><p>Статья носит информационный характер и не является медицинской рекомендацией.</p>', NULL, NULL, NULL);
