INSERT INTO blog_post_translations (id, post_id, locale, slug, title, excerpt, content_json, content_html, table_of_contents_json, faq_json, seo_meta_id) VALUES ('6510d53a-b2a9-489b-9aad-3bc15099b41f', '53a38caa-8dfd-49a4-a9ae-6dce2c071707', 'ru', 'psikhosomatika-chto-eto', 'Психосоматика: что это и как тело говорит языком эмоций', 'Психосоматика: что это, как эмоции влияют на тело, почему врачи не находят причину болезни. Полный гид по психосоматическим симптомам и методам работы через гипнотерапию.', NULL, '<p>Тело и психика неразрывно связаны. Психосоматика — это направление, изучающее, как эмоциональные состояния и психологические проблемы влияют на физическое здоровье. Когда психика не может справиться с напряжением, тело берёт удар на себя.</p><h2>Как эмоции влияют на тело</h2><p>Подавленный гнев — напряжение в челюсти и плечах. Непрожитая печаль — тяжесть в груди. Хроническая тревога — проблемы с пищеварением, головные боли, тахикардия.</p><h2>Как гипнотерапия помогает при психосоматике</h2><p>Гипнотерапия работает с первопричиной на уровне подсознания, позволяя высвободить подавленные эмоции и убрать телесные симптомы без лекарств.</p><p>Статья носит информационный характер и не является медицинской рекомендацией.</p>', NULL, NULL, NULL);
